import { styled } from 'styled-components'

const StyledCardTag = styled.div`
  height: 26px;
  width: max-content;
  padding: 6px 4px;
  background-color: #e66767;
  color: #ffebd9;
  text-align: center;
  font-size: 12px;
  font-weight: 700;
  display: flex;
  align-items: center;
`

export default StyledCardTag
